<template>
  <div class="floor_container">
    <div 
      class="floor"
      v-for="(item,k) of list"
      :key="k"
    >
      <div class="floor_title_list">
        <h3 class="floor_title">
          {{ item.title }}
        </h3>
        <div class="right_list_item">
          <a 
            class="floor_item"
            v-for="(item,index) of item.navTitle"
            :key="index"
            :href="item.href"
          >{{ item }}</a>
        </div>
      </div>
      <div 
        class="item"
        v-for="(item,k) of item.result"
        :key="k"
      >
        <div 
          class="item_container"
          @click.stop="onDetail"
          :data-id="item.id"
          :data-pid="item.pid"
        >
          <div class="item_img_address">
            <img :src="item.foot_img">
            <div class="item_address">
              <i class="fa fa-user-o" />{{ item.address }}
            </div>
          </div>
          <div class="title">
            {{ item.foot_name }}
          </div>
          <div class="notice">
            {{ item.foot_notice }}
          </div>
          <div 
            class="reduce"
            v-if="item.reduce_price"
          >
            立减{{ item.reduce_price|fixTwo }}元
          </div>
          <div class="price">
            ￥<span class="newPrice">{{ item.new_price }}</span>
            <span class="oldPrice"> 价值￥<del>{{ item.old_price }}</del></span>
          </div>
          <div class="buy_infomation">
            <span class="source">{{ item.foot_source }}</span>分
            <span class="has_sold">已售{{ item.foot_sold }}份</span>
          </div>
        </div>
      </div>
    </div>
    <router-view />
  </div>
</template>
<script>
export default {
    props:{
        list:{
            type:Array,
            default  (){
                return [];
            }
        }
    },
    filters:{
        fixTwo (value){
            return value.toFixed(2);

        }

    },
    methods:{
        
        // 展示列表数据详情页
        onDetail (event){
            let currentElementId = event.target.dataset.id,
                currentElementPid = event.target.dataset.pid;
            this.$router.push({
                path:`/productionDetail/${currentElementPid}/${currentElementId}`
            });
        }
    }
    
};
</script>
<style lang="scss" scoped>
.floor_container{
    width:1200px;
    margin:0 auto;
    overflow:hidden;
    .floor{
        overflow:hidden;
        margin-top:20px;
        .floor_title_list{
            height:20px;
            padding:0px 5px 0 0;
            line-height:20px;
            .floor_title{
                font-weight:bold;
                display:inline-block;
                letter-spacing: 2px;

            }
            .right_list_item{
                display:inline-block;
                margin-left:720px;
                font-size:13px;
                .floor_item{
                    border-left:1px solid rgb(201,201,201);
                    padding:0 20px;
                    &:first-child{
                        border:none;
                    }
                    &:last-child{
                        background:url(../images/next.png) 53px 4px no-repeat;
                        
                    }
                    &:hover{
                        color:royalblue;
                        text-decoration: underline;
                    }
                
                
            }

            }
            


        }
        .item{
            width:230px;
            height:280px;
            float:left;
            padding:10px 5px 23px 5px ;
            overflow:hidden;
            border-bottom:1px solid rgb(201,201,201);
            .item_container{
                width:100%;
                height:100%;
                padding-top:5px;
                position:relative;
                
                &::after{
                    content: "";
                    width: 237px ;
                    height:100%;
                    display:inline-block;
                    position:absolute;
                    top:0;
                    left:-5px;
                    cursor: pointer;
                    border:1px solid transparent;


                    
                }

                &:hover{
                    &::after{
                        border:1px solid #e4007f;

                    }
                    .item_address{
                        opacity:0.8;
                        background-color:rgb(49,49,49);
                    }
                }
                .title{
                    font-size:15px;
                    font-weight:bold;
                    margin-top:10px;
                    letter-spacing:2px;
                }
                .notice{
                    font-size:13px;
                    color:rgb(98,98,98);
                }
                .reduce{
                    background-color:#e4007f;
                    color:whitesmoke;
                    border-radius:2px;
                    padding:0 5px;
                    display:inline;
                    position:relative;
                    top:20px;
                }
                .price{
                    position: absolute;
                    top:230px;
                    color:#e4007f;
                    font-size:16px;
                    .newPrice{
                    font-size:22px;
                    font-weight:500;
                    }
                    .oldPrice{
                        font-size:13px;
                        margin-left:5px;
                        color:rgb(160,160,160);
                    }

                }
                .buy_infomation{
                    position: absolute;;
                    top:265px;
                    font-size:12px;
                     color:rgb(160,160,160);
                     .source{
                         color:rgb(0,117,169);
                     }
                     .has_sold{
                         margin-left:117px;
                     }
                }
            }
            .item_img_address{
                position:relative;
                width:100%;
                height:135px;
                
                img{
                    width:100%;
                    height:100%;

                }
                .item_address{
                    padding-left:5px;
                    width:225px;
                    height:30px;
                    position:absolute;
                    bottom:0px;
                    color:whitesmoke;
                    transition: all 0.3s ease-in;
                    opacity:0;
                    font-size:13px;
                    line-height:30px;
                    font-weight: 600;
                    .fa{
                        padding-right:5px;
                    }
                }

            }
        }

    }

}

</style>


