import Vue from "vue";
import VueRouter from "vue-router";
import store from "../store/index";
Vue.use(VueRouter);
import myShop from "../detail/route/shop.vue";
import myUser from "../detail/route/user.vue";

// 首页
import myIndex from "../index/container.vue";
import myDetail from "../detail/route/detail.vue";
// 用户订单
const  myPay = () => import(/* webpackChunkName:"pay" */ "../pay/pay.vue"),
    // 商品详情页
    productionDetail = () => import(/* webpackChunkName: "detail" */ "../detail/introduce.vue"),
    //   分类下全部商品展示页
    myList = () => import( /* webpackChunkName:"list" */ "../list/list.vue"),
    // 用户登陆
    myLogin = () => import( /* webpackChunkName: "myLogin " */ "../login/login.vue"),
    // 用户注册
    myRegister = () => import( /* webpackChunkName: "myRegister"  */ "../register/register.vue"),
    router = new VueRouter({
        linkActiveClass:"active",
        routes:[
            {
                path:"/",
                redirect:{
                    name:"index"
                }
            },
            // 首页路由
            {
                path:"/index",
                component:myIndex,
                name:"index",
                meta:{
                    title:"o2o团购网",
                    keepAlive:false
                },
                // 缓存首页
                beforeEnter: (to, from, next) => {
                    if(from.name === ("detail" || "list")){
                        to.meta.keepAlive = true;
                    }
                    next();
                }

            },
            // 商品详情页路由
            {
                path:"/productionDetail/:currentElementPid/:currentElementId",
                component: productionDetail,
                children:[
                    {
                        path:"",
                        redirect:{
                            name:"detail"
                        }
                    },
                    {
                        path: "detail",
                        component: myDetail,
                        name: "detail",
                        meta:{
                            isSaved:true,
                            // 不缓存
                            keepAlive:false,
                            title:"商品详情"
                        
                        }
                    }, {
                        path: "shop",
                        component: myShop,
                        name: "shop",
                        meta: {
                            isSaved: true
                        }
                    }, {
                        path: "user",
                        component: myUser,
                        name: "user",
                        meta: {
                            isSaved: true
                        }
                    }
                ],
                meta:{
                    
                }
            },
            // 用户订单路由
            {
                path:"/pay",
                component:myPay,
                name:"pay",
                meta:{
                    isLogin:true,
                    title:"用户订单中心"
                }
            },
            // 用户登陆路由
            {
                path:"/login",
                component:myLogin,
                name:"login",
                meta:{
                    title:"用户登陆"
                }
            },{
                path:"/register",
                component:myRegister,
                name:"register",
                meta:{
                    title:"用户注册"
                }
            },
            // 分类下的全部商品展示页路由
            {
                path:"/list/:currentElementId",
                component: myList,
                name:"list",
                meta:{
                    title:"全部商品",
                    keepAlive:false,
                },
                beforeEnter: (to, from, next) => {
                    if(from.name === "detail"){
                        to.meta.keepAlive = true;
                    }

                    next();
                }
            }
        ],
        scrollBehavior(to, from, savedPosition){
            if (savedPosition){
                return savedPosition;

            }
            return {x:0,y:0};
        
        }

    });

router.beforeEach((to,from,next) => {
    // 切换不同路由间的标题
    if(to.meta && to.meta.title && (document.title !== to.meta.title)){
        document.title = to.meta.title;
    }
    // 验证用户登陆
    if(to.meta.isLogin){
        const token = store.state.token || localStorage.getItem("token");
        if(token){
            next();
        }else{
            next({
                path:"/login",
                query:{
                    redirect:from.fullPath
                }

            });
        }

    }else{
        next();
    }

});


export default router;